{"command": "cd /data/zrwang/auto-opt/utils/llvm-63749 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp 3011 3045

// (icmp ne X, -1) & (icmp ule (add X, 1), Y) -> (icmp ult X, Y)
// (icmp eq X, -1) | (icmp uge (add X, 1), Y) -> (icmp ugt X, Y)
static Value *foldAndOrOfICmpEqAllOnesAndICmpAdd(ICmpInst *LHS, ICmpInst *RHS,
                                                 bool IsAnd, bool IsLogical,
                                                 IRBuilderBase &Builder) {
  ICmpInst::Predicate LPred =
      IsAnd ? LHS->getInversePredicate() : LHS->getPredicate();
  ICmpInst::Predicate RPred =
      IsAnd ? RHS->getInversePredicate() : RHS->getPredicate();
  Value *LHS0 = LHS->getOperand(0);
  if (LPred != ICmpInst::ICMP_EQ || !match(LHS->getOperand(1), m_AllOnes()) ||
      !LHS0->getType()->isIntOrIntVectorTy() ||
      !(LHS->hasOneUse() || RHS->hasOneUse()))
    return nullptr;

  Value *Other;
  if (RPred == ICmpInst::ICMP_UGT &&
      match(RHS->getOperand(0), m_c_Add(m_Specific(LHS0), m_One())) &&
      RHS->getOperand(1) != LHS0)
    Other = RHS->getOperand(1);
  else if (RPred == ICmpInst::ICMP_UGE &&
           match(RHS->getOperand(1), m_c_Add(m_Specific(LHS0), m_One())) &&
           RHS->getOperand(0) != LHS0)
    Other = RHS->getOperand(0);
  else
    return nullptr;

  if (IsLogical)
    Other = Builder.CreateFreeze(Other);
  return Builder.CreateICmp(IsAnd ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGT,
                            LHS0, Other);
}
CODEEOF"}

